  ('social-worker-moex-01841', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關義務論的敘述何者錯誤？', '["有道德價值的行為必須是因義務而為的", "一個因義務而為之行為，其道德價值不在於由此行為達成的目的，而在於決定此行為的準則", "義務是尊敬法則的必然行為", "在道德規範上，義務論主張道德規範是為了增益人群之樂，減免其苦"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01842', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '多年來社會工作學者和實務工作者致力於探討發展性社會工作的概念，下列何者不是發展性社會工作的 理念？', '["變遷的概念", "優勢與充權", "社會整合", "不依賴國際創新的分享"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01843', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '根據芮摩（Reamer）處理倫理困境對照比較原則，下列敘述何者錯誤？', '["個人的自決權優於他人的基本福祉權", "以維護人類生命、健康、尊嚴並避免傷害為優先", "個人自我決定權優於其自身基本福祉的考慮", "人們在自由意志下同意遵守的法律、機構規定等義務，凌駕於個人的信仰、價值與原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01844', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下對於臺灣社會工作專業發展的敘述，何者正確？', '["臺灣最早的社會工作學系，乃是1965年臺南神學院成立的社會服務科", "1972年臺灣省推動「小康計畫」所聘用的社工員，乃是臺灣最早期的社會工作員", "1991年國內擬出第一個社會工作師法草案，歷經多年來的討論和倡議行動，《社會工作師法》於1998 年3月完成立法三讀通過", "2008 年《社會工作師法》三讀修正通過，社工師分級制確立，明訂社工師完成相關專科訓練並通過甄 審後，即可請領專科社工師證書"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01845', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '依生態觀點（ecological perspectives），下列何者是指社會、政治、經濟與文化制度？', '["微視系統（micro-system）", "長程貫時系統（chronosystem）", "巨視系統（macro-system）", "居間系統（mezzo-system）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01846', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下的敘述，那一個最符合國際社會工作者聯盟（International Federation of Social Workers）（2014）對 社會工作的全球定義？', '["一個以實踐為本的專業和學術領域，社會工作推動社會改變和發展、社會凝聚、和人民的充權及解放", "社會工作專業在提供人性有效的社會服務給個人、家庭、團體、社區和社會", "社會工作是創造有利於達成目標的社會條件的一項專業活動", "社會工作者尋求、認定與強化個人、團體和社會的最大潛能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01847', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '義務論者提出專業工作應具有兩種義務，分別為消極和積極義務，下列何者為社會工作倫理的積極義務？', '["應尊重案主的自決能力", "不得無故洩漏案主的秘密", "不得出借證照予他人", "應致力機構政策及服務效能的改進"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01848', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '倫理是人與人、人與其他生物、人與環境間的行為準則，社會工作者該如何遵循，下列有關社會工作倫 理學觀點的敘述何者正確？', '["效用主義在倫理上的限制，在於最大的快樂是廣泛模糊的概念，很難以理性地計量", "康德主義是支持以宗教來形成人們的道德信念", "權利論者認為社會應保障每個個體免於被侵犯的自由，強調自由是一種義務", "馬克思主義在倫理的考量係強調優勢觀點，挑戰政治結構，無須為案主辯護"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01849', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於下列各社會工作理論的處遇目標之敘述何者正確？', '["危機介入取向：協助案主處理情緒感受和幫助案主學習適當的壓力因應方法，避免再陷入危機", "任務中心取向：在於增進案主運用環境資源的能力，協助重建或建立案主與環境的良好交流", "生態觀點：協助案主在維持靜態與動態成長間作抉擇與調適", "系統理論觀點：協助案主釐清相關問題與優先順序，並決定欲改變的目標及其具體步驟和方法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
